Here is the implementation of the Template Method design pattern for sorting algorithms in Python:

```python
from abc import ABC, abstractmethod

class SortAlgorithm(ABC):
    @abstractmethod
    def sort(self, arr):
        pass

    @abstractmethod
    def compare(self, i, j):
        pass

    @abstractmethod
    def swap(self, i, j, arr):
        pass

class BubbleSort(SortAlgorithm):
    def sort(self, arr):
        n = len(arr)
        for i in range(n):
            for j in range(0, n - i - 1):
                if self.compare(j, j + 1):
                    self.swap(j, j + 1, arr)
        return arr

    def compare(self, i, j):
        return arr[i] > arr[j]

    def swap(self, i, j, arr):
        arr[i], arr[j] = arr[j], arr[i]

class SelectionSort(SortAlgorithm):
    def sort(self, arr):
        n = len(arr)
        for i in range(n):
            min_idx = i
            for j in range(i + 1, n):
                if self.compare(j, min_idx):
                    min_idx = j
            self.swap(i, min_idx, arr)
        return arr

    def compare(self, i, j):
        return arr[i] > arr[j]

    def swap(self, i, j, arr):
        arr[i], arr[j] = arr[j], arr[i]

